遍历字符串提取数字字符，存到 vector，从大到小排序。如果最大的数字不是 0 则直接拼接返回；如果最大的是 0 则结果就是 0。注意正整数不能以 0 开头。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    string s;
    cin >> s;
    vector<char> digits;
    for (char c : s) {
        if (c >= '0' && c <= '9') digits.push_back(c);
    }
    sort(digits.rbegin(), digits.rend());
    if (digits.empty() || digits[0] == '0') { cout << 0 << endl; return 0; }
    for (char c : digits) cout << c;
    cout << endl;
    return 0;
}
```

将花色映射到 0-3，点数映射到 0-12。用布尔数组 have[4][13] 标记。统计 have 中 true 的个数 cnt，52 - cnt 即为答案。注意：重复牌只算一次。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    bool have[4][13] = {false};
    int n;
    cin >> n;
    string s;
    for (int i = 0; i < n; i++) {
        cin >> s;
        int suit, rank;
        if (s[0] == 'D') suit = 0;
        else if (s[0] == 'C') suit = 1;
        else if (s[0] == 'H') suit = 2;
        else suit = 3;
        if (s[1] >= '2' && s[1] <= '9') rank = s[1] - '1';
        else if (s[1] == 'A') rank = 0;
        else if (s[1] == 'T') rank = 9;
        else if (s[1] == 'J') rank = 10;
        else if (s[1] == 'Q') rank = 11;
        else rank = 12;
        have[suit][rank] = true;
    }
    int cnt = 0;
    for (int i = 0; i < 4; i++)
        for (int j = 0; j < 13; j++)
            if (have[i][j]) cnt++;
    cout << 52 - cnt << endl;
    return 0;
}
```

数学规律：每天拿走的苹果数为 ceil(剩余/3)。总天数用循环累加直到 n=0。编号 n 苹果被拿走的天数：每天检查 n 是否在当天被拿走（即 n%3==1），如果是则记录天数。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    int n, day = 0, ans_day = 0;
    cin >> n;
    int remain = n;
    while (remain > 0) {
        day++;
        int take = (remain + 2) / 3;
        if (remain % 3 == 1 && ans_day == 0) ans_day = day;
        remain -= take;
    }
    cout << day << " " << ans_day << endl;
    return 0;
}
```

用 long long 累乘，每次乘 a 后判断是否超过 1e9。注意几个优化：a=1 时直接输出 1；b=0 时输出 1；循环中若 result > 1e9 则提前退出输出 -1。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    long long a, b, ans = 1;
    cin >> a >> b;
    if (a == 1) { cout << 1 << endl; return 0; }
    for (long long i = 0; i < b; i++) {
        ans *= a;
        if (ans > 1000000000) { cout << -1 << endl; return 0; }
    }
    cout << ans << endl;
    return 0;
}
```
